                        if (j == (array.length - 1)) {
                            // last dummy point
                            double x = segment.getLine().toSubSpace(segment.getStart()).getX();
                            x += FastMath.max(1.0, FastMath.abs(x / 2));
                            array[j++] = segment.getLine().toSpace(new Vector1D(x));
