                    vertices[i++] = array;
                } else {
                    final Vector2D[] array = new Vector2D[loop.size()];
                    int j = 0;
                    for (Segment segment : loop) {
                        array[j++] = segment.getStart();
                    }
                    vertices[i++] = array;
                }
            }
        }
    }
    return vertices.clone();
