    int ii = 0;
    for (int i = 0; i < n; i++) {
        f[i] = data[ii];
        int k = n >> 1;
        while (ii >= k && k > 0) {
            ii -= k;
            k >>= 1;
        }
        ii += k;
    }
    // the bottom base-4 round
    for (int i = 0; i < n; i += 4) {
        final Complex a = f[i].add(f[i + 1]);
        final Complex b = f[i + 2].add(f[i + 3]);
        final Complex c = f[i].subtract(f[i + 1]);
        final Complex d = f[i + 2].subtract(f[i + 3]);
        final Complex e1 = c.add(d.multiply(Complex.I));
