        // y(ti) - y(t0) - di y'(t0) and y'(ti) - y'(t0)
        final double[] aI = a[2 * i - 2];
        final double[] aDotI = a[2 * i - 1];
        for (int j = 0; j < aI.length; ++j) {
            dikM1Ohk *= ratio;
            aI[j] = di * dikM1Ohk;
            aDotI[j] = (j + 2) * dikM1Ohk;
