    // The simplex has n + 1 points if dimension is n.
    final int n = getDimension();
    // Interesting values.
    final RealPointValuePair best = getPoint(0);
    final RealPointValuePair secondBest = getPoint(n - 1);
    final RealPointValuePair worst = getPoint(n);
    final double[] xWorst = worst.getPointRef();
    // Compute the centroid of the best vertices (dismissing the worst
    // point at index n).
    final double[] centroid = new double[n];
    for (int i = 0; i < n; i++) {
        final double[] x = getPoint(i).getPointRef();
        for (int j = 0; j < n; j++) {
            centroid[j] += x[j];
        }
    }
    final double scaling = 1.0 / n;
    for (int j = 0; j < n; j++) {
        centroid[j] *= scaling;
    }
    // compute the reflection point
    final double[] xR = new double[n];
    for (int j = 0; j < n; j++) {
        xR[j] = centroid[j] + rho * (centroid[j] - xWorst[j]);
    }
    final RealPointValuePair reflected = new RealPointValuePair(xR, evaluationFunction.value(xR), false);
    if (comparator.compare(best, reflected) <= 0 && comparator.compare(reflected, secondBest) < 0) {
        // Accept the reflected point.
        replaceWorstPoint(reflected, comparator);
    } else if (comparator.compare(reflected, best) < 0) {
        // Compute the expansion point.
        final double[] xE = new double[n];
        for (int j = 0; j < n; j++) {
            xE[j] = centroid[j] + khi * (xR[j] - centroid[j]);
        }
        final RealPointValuePair expanded = new RealPointValuePair(xE, evaluationFunction.value(xE), false);
        if (comparator.compare(expanded, reflected) < 0) {
            // Accept the expansion point.
            replaceWorstPoint(expanded, comparator);
        } else {
            // Accept the reflected point.
            replaceWorstPoint(reflected, comparator);
        }
    } else {
        if (comparator.compare(reflected, worst) < 0) {
            // Perform an outside contraction.
            final double[] xC = new double[n];
            for (int j = 0; j < n; j++) {
                xC[j] = centroid[j] + gamma * (xR[j] - centroid[j]);
            }
            final RealPointValuePair outContracted = new RealPointValuePair(xC, evaluationFunction.value(xC), false);
            if (comparator.compare(outContracted, reflected) <= 0) {
                // Accept the contraction point.
                replaceWorstPoint(outContracted, comparator);
                return;
            }
        } else {
            // Perform an inside contraction.
            final double[] xC = new double[n];
            for (int j = 0; j < n; j++) {
